#include <stdio.h>
#include <stdint.h>

const int64_t MOD = 1000000007LL;

int64_t modPow(int64_t base, int64_t exp) {
    int64_t res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int maxVal = 0, cnt = 0;
        for (int i = 0; i < n; ++i) {
            int x; scanf("%d", &x);
            if (x > maxVal) {
                maxVal = x;
                cnt = 1;
            } else if (x == maxVal) {
                ++cnt;
            }
        }
        int64_t ans = (modPow(2, cnt) - 1 + MOD) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

