code.Python3:
#!/usr/bin/env python3
import sys
MOD = 1_000_000_007

def mod_pow(base, exp):
    res = 1
    base %= MOD
    while exp:
        if exp & 1:
            res = (res * base) % MOD
        base = (base * base) % MOD
        exp >>= 1
    return res

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        n = next(it)
        max_val = 0
        cnt = 0
        for _ in range(n):
            x = next(it)
            if x > max_val:
                max_val = x
                cnt = 1
            elif x == max_val:
                cnt += 1
        ans = (mod_pow(2, cnt) - 1) % MOD
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

